public struct RgbaColor {
    public var r: Float
    public var g: Float
    public var b: Float
    public var a: Float

    /// Default memberwise initializers are never public by default, so we
    /// declare one manually.
    public init(r: Float, g: Float, b: Float, a: Float) {
        self.r = r
        self.g = g
        self.b = b
        self.a = a
    }
}

extension RgbaColor: Equatable, Hashable {
    public static func == (lhs: RgbaColor, rhs: RgbaColor) -> Bool {
        if lhs.r != rhs.r {
            return false
        }
        if lhs.g != rhs.g {
            return false
        }
        if lhs.b != rhs.b {
            return false
        }
        if lhs.a != rhs.a {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(r)
        hasher.combine(g)
        hasher.combine(b)
        hasher.combine(a)
    }
}

